window.BIBLE["Ecclesiastes"] = {"1":{"chapter":"1","title":"Ecclesiastes 1","verses":{"1":{"text":"The words of the Preacher, the son of David, king in Jerusalem.","ref":"Ecclesiastes 1:1","synthesized":"The words of the Preacher, the son of David, king in Jerusalem.","sources":{"KJV":{"text":"The words of the Preacher, the son of David, king in Jerusalem."}},"definableWords":["son","king"],"peopleInVerse":["David"]},"2":{"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity.","ref":"Ecclesiastes 1:2","synthesized":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity.","sources":{"KJV":{"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"What profit hath a man of all his labour which he taketh under the sun?","ref":"Ecclesiastes 1:3","synthesized":"What profit hath a man of all his labour which he taketh under the sun?","sources":{"KJV":{"text":"What profit hath a man of all his labour which he taketh under the sun?"}},"definableWords":["man"],"peopleInVerse":[]},"4":{"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever.","ref":"Ecclesiastes 1:4","synthesized":"One generation passeth away, and another generation cometh: but the earth abideth for ever.","sources":{"KJV":{"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever."}},"definableWords":["one","earth"],"peopleInVerse":[]},"5":{"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose.","ref":"Ecclesiastes 1:5","synthesized":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose.","sources":{"KJV":{"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits.","ref":"Ecclesiastes 1:6","synthesized":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits.","sources":{"KJV":{"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again.","ref":"Ecclesiastes 1:7","synthesized":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again.","sources":{"KJV":{"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again."}},"definableWords":["sea"],"peopleInVerse":[]},"8":{"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing.","ref":"Ecclesiastes 1:8","synthesized":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing.","sources":{"KJV":{"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing."}},"definableWords":["man"],"peopleInVerse":[]},"9":{"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun.","ref":"Ecclesiastes 1:9","synthesized":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun.","sources":{"KJV":{"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us.","ref":"Ecclesiastes 1:10","synthesized":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us.","sources":{"KJV":{"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us."}},"definableWords":["see"],"peopleInVerse":[]},"11":{"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after.","ref":"Ecclesiastes 1:11","synthesized":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after.","sources":{"KJV":{"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"I the Preacher was king over Israel in Jerusalem.","ref":"Ecclesiastes 1:12","synthesized":"I the Preacher was king over Israel in Jerusalem.","sources":{"KJV":{"text":"I the Preacher was king over Israel in Jerusalem."}},"definableWords":["king","Israel"],"peopleInVerse":[]},"13":{"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith.","ref":"Ecclesiastes 1:13","synthesized":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith.","sources":{"KJV":{"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith."}},"definableWords":["wisdom","heaven","God","sons","man"],"peopleInVerse":[]},"14":{"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit.","ref":"Ecclesiastes 1:14","synthesized":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit.","sources":{"KJV":{"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit."}},"definableWords":["works","spirit"],"peopleInVerse":[]},"15":{"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered.","ref":"Ecclesiastes 1:15","synthesized":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered.","sources":{"KJV":{"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered."}},"definableWords":["made"],"peopleInVerse":[]},"16":{"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge.","ref":"Ecclesiastes 1:16","synthesized":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge.","sources":{"KJV":{"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge."}},"definableWords":["great","wisdom","knowledge"],"peopleInVerse":[]},"17":{"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit.","ref":"Ecclesiastes 1:17","synthesized":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit.","sources":{"KJV":{"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit."}},"definableWords":["wisdom","spirit"],"peopleInVerse":[]},"18":{"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow.","ref":"Ecclesiastes 1:18","synthesized":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow.","sources":{"KJV":{"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow."}},"definableWords":["wisdom","knowledge"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"Ecclesiastes 2","verses":{"1":{"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity.","ref":"Ecclesiastes 2:1","synthesized":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity.","sources":{"KJV":{"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"I said of laughter, It is mad: and of mirth, What doeth it?","ref":"Ecclesiastes 2:2","synthesized":"I said of laughter, It is mad: and of mirth, What doeth it?","sources":{"KJV":{"text":"I said of laughter, It is mad: and of mirth, What doeth it?"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life.","ref":"Ecclesiastes 2:3","synthesized":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life.","sources":{"KJV":{"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life."}},"definableWords":["wisdom","till","see","good","sons","men","heaven","days","life"],"peopleInVerse":[]},"4":{"text":"I made me great works; I builded me houses; I planted me vineyards:","ref":"Ecclesiastes 2:4","synthesized":"I made me great works; I builded me houses; I planted me vineyards:","sources":{"KJV":{"text":"I made me great works; I builded me houses; I planted me vineyards:"}},"definableWords":["made","great","works"],"peopleInVerse":[]},"5":{"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:","ref":"Ecclesiastes 2:5","synthesized":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:","sources":{"KJV":{"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:"}},"definableWords":["made","trees"],"peopleInVerse":[]},"6":{"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:","ref":"Ecclesiastes 2:6","synthesized":"I made me pools of water, to water therewith the wood that bringeth forth trees:","sources":{"KJV":{"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:"}},"definableWords":["made","water","trees"],"peopleInVerse":[]},"7":{"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:","ref":"Ecclesiastes 2:7","synthesized":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:","sources":{"KJV":{"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:"}},"definableWords":["servants","house","great","cattle"],"peopleInVerse":[]},"8":{"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts.","ref":"Ecclesiastes 2:8","synthesized":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts.","sources":{"KJV":{"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts."}},"definableWords":["kings","men","women","sons"],"peopleInVerse":[]},"9":{"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me.","ref":"Ecclesiastes 2:9","synthesized":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me.","sources":{"KJV":{"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me."}},"definableWords":["great","wisdom"],"peopleInVerse":[]},"10":{"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour.","ref":"Ecclesiastes 2:10","synthesized":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour.","sources":{"KJV":{"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun.","ref":"Ecclesiastes 2:11","synthesized":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun.","sources":{"KJV":{"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun."}},"definableWords":["works","spirit"],"peopleInVerse":[]},"12":{"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done.","ref":"Ecclesiastes 2:12","synthesized":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done.","sources":{"KJV":{"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done."}},"definableWords":["wisdom","man","king"],"peopleInVerse":[]},"13":{"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness.","ref":"Ecclesiastes 2:13","synthesized":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness.","sources":{"KJV":{"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness."}},"definableWords":["saw","wisdom","light","darkness"],"peopleInVerse":[]},"14":{"text":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all.","ref":"Ecclesiastes 2:14","synthesized":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all.","sources":{"KJV":{"text":"The wise man’s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all."}},"definableWords":["man","darkness","one"],"peopleInVerse":[]},"15":{"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity.","ref":"Ecclesiastes 2:15","synthesized":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity.","sources":{"KJV":{"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool.","ref":"Ecclesiastes 2:16","synthesized":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool.","sources":{"KJV":{"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool."}},"definableWords":["days","man"],"peopleInVerse":[]},"17":{"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit.","ref":"Ecclesiastes 2:17","synthesized":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit.","sources":{"KJV":{"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit."}},"definableWords":["life","work","spirit"],"peopleInVerse":[]},"18":{"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me.","ref":"Ecclesiastes 2:18","synthesized":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me.","sources":{"KJV":{"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me."}},"definableWords":["man"],"peopleInVerse":[]},"19":{"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity.","ref":"Ecclesiastes 2:19","synthesized":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity.","sources":{"KJV":{"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity."}},"definableWords":["man","or","rule"],"peopleInVerse":[]},"20":{"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun.","ref":"Ecclesiastes 2:20","synthesized":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun.","sources":{"KJV":{"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil.","ref":"Ecclesiastes 2:21","synthesized":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil.","sources":{"KJV":{"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil."}},"definableWords":["man","wisdom","knowledge","great","evil"],"peopleInVerse":[]},"22":{"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?","ref":"Ecclesiastes 2:22","synthesized":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?","sources":{"KJV":{"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?"}},"definableWords":["man"],"peopleInVerse":[]},"23":{"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity.","ref":"Ecclesiastes 2:23","synthesized":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity.","sources":{"KJV":{"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity."}},"definableWords":["days","rest","night"],"peopleInVerse":[]},"24":{"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God.","ref":"Ecclesiastes 2:24","synthesized":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God.","sources":{"KJV":{"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God."}},"definableWords":["man","make","soul","good","saw","God"],"peopleInVerse":[]},"25":{"text":"For who can eat, or who else can hasten hereunto, more than I?","ref":"Ecclesiastes 2:25","synthesized":"For who can eat, or who else can hasten hereunto, more than I?","sources":{"KJV":{"text":"For who can eat, or who else can hasten hereunto, more than I?"}},"definableWords":["or"],"peopleInVerse":[]},"26":{"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit.","ref":"Ecclesiastes 2:26","synthesized":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit.","sources":{"KJV":{"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit."}},"definableWords":["God","man","good","wisdom","knowledge","spirit"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"Ecclesiastes 3","verses":{"1":{"text":"To every thing there is a season, and a time to every purpose under the heaven:","ref":"Ecclesiastes 3:1","synthesized":"To every thing there is a season, and a time to every purpose under the heaven:","sources":{"KJV":{"text":"To every thing there is a season, and a time to every purpose under the heaven:"}},"definableWords":["heaven"],"peopleInVerse":[]},"2":{"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;","ref":"Ecclesiastes 3:2","synthesized":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;","sources":{"KJV":{"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;"}},"definableWords":["die"],"peopleInVerse":[]},"3":{"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;","ref":"Ecclesiastes 3:3","synthesized":"A time to kill, and a time to heal; a time to break down, and a time to build up;","sources":{"KJV":{"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;","ref":"Ecclesiastes 3:4","synthesized":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;","sources":{"KJV":{"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;","ref":"Ecclesiastes 3:5","synthesized":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;","sources":{"KJV":{"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;","ref":"Ecclesiastes 3:6","synthesized":"A time to get, and a time to lose; a time to keep, and a time to cast away;","sources":{"KJV":{"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;"}},"definableWords":["keep"],"peopleInVerse":[]},"7":{"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;","ref":"Ecclesiastes 3:7","synthesized":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;","sources":{"KJV":{"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;"}},"definableWords":["keep"],"peopleInVerse":[]},"8":{"text":"A time to love, and a time to hate; a time of war, and a time of peace.","ref":"Ecclesiastes 3:8","synthesized":"A time to love, and a time to hate; a time of war, and a time of peace.","sources":{"KJV":{"text":"A time to love, and a time to hate; a time of war, and a time of peace."}},"definableWords":["love","peace"],"peopleInVerse":[]},"9":{"text":"What profit hath he that worketh in that wherein he laboureth?","ref":"Ecclesiastes 3:9","synthesized":"What profit hath he that worketh in that wherein he laboureth?","sources":{"KJV":{"text":"What profit hath he that worketh in that wherein he laboureth?"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it.","ref":"Ecclesiastes 3:10","synthesized":"I have seen the travail, which God hath given to the sons of men to be exercised in it.","sources":{"KJV":{"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it."}},"definableWords":["God","sons","men"],"peopleInVerse":[]},"11":{"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.","ref":"Ecclesiastes 3:11","synthesized":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.","sources":{"KJV":{"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end."}},"definableWords":["made","man","work","God","beginning"],"peopleInVerse":[]},"12":{"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life.","ref":"Ecclesiastes 3:12","synthesized":"I know that there is no good in them, but for a man to rejoice, and to do good in his life.","sources":{"KJV":{"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life."}},"definableWords":["good","man","life"],"peopleInVerse":[]},"13":{"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God.","ref":"Ecclesiastes 3:13","synthesized":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God.","sources":{"KJV":{"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God."}},"definableWords":["man","good","God"],"peopleInVerse":[]},"14":{"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him.","ref":"Ecclesiastes 3:14","synthesized":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him.","sources":{"KJV":{"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him."}},"definableWords":["God","men","fear"],"peopleInVerse":[]},"15":{"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past.","ref":"Ecclesiastes 3:15","synthesized":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past.","sources":{"KJV":{"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past."}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there.","ref":"Ecclesiastes 3:16","synthesized":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there.","sources":{"KJV":{"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there."}},"definableWords":["saw","judgment","righteousness","iniquity"],"peopleInVerse":[]},"17":{"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work.","ref":"Ecclesiastes 3:17","synthesized":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work.","sources":{"KJV":{"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work."}},"definableWords":["God","righteous","work"],"peopleInVerse":[]},"18":{"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts.","ref":"Ecclesiastes 3:18","synthesized":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts.","sources":{"KJV":{"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts."}},"definableWords":["sons","men","God","see"],"peopleInVerse":[]},"19":{"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity.","ref":"Ecclesiastes 3:19","synthesized":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity.","sources":{"KJV":{"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity."}},"definableWords":["sons","men","one","breath","man"],"peopleInVerse":[]},"20":{"text":"All go unto one place; all are of the dust, and all turn to dust again.","ref":"Ecclesiastes 3:20","synthesized":"All go unto one place; all are of the dust, and all turn to dust again.","sources":{"KJV":{"text":"All go unto one place; all are of the dust, and all turn to dust again."}},"definableWords":["one"],"peopleInVerse":[]},"21":{"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?","ref":"Ecclesiastes 3:21","synthesized":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?","sources":{"KJV":{"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?"}},"definableWords":["spirit","man","earth"],"peopleInVerse":[]},"22":{"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?","ref":"Ecclesiastes 3:22","synthesized":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?","sources":{"KJV":{"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?"}},"definableWords":["man","works","see"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"Ecclesiastes 4","verses":{"1":{"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.","ref":"Ecclesiastes 4:1","synthesized":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.","sources":{"KJV":{"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive.","ref":"Ecclesiastes 4:2","synthesized":"Wherefore I praised the dead which are already dead more than the living which are yet alive.","sources":{"KJV":{"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive."}},"definableWords":["living"],"peopleInVerse":[]},"3":{"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun.","ref":"Ecclesiastes 4:3","synthesized":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun.","sources":{"KJV":{"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun."}},"definableWords":["evil","work"],"peopleInVerse":[]},"4":{"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit.","ref":"Ecclesiastes 4:4","synthesized":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit.","sources":{"KJV":{"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit."}},"definableWords":["work","man","spirit"],"peopleInVerse":[]},"5":{"text":"The fool foldeth his hands together, and eateth his own flesh.","ref":"Ecclesiastes 4:5","synthesized":"The fool foldeth his hands together, and eateth his own flesh.","sources":{"KJV":{"text":"The fool foldeth his hands together, and eateth his own flesh."}},"definableWords":["flesh"],"peopleInVerse":[]},"6":{"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit.","ref":"Ecclesiastes 4:6","synthesized":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit.","sources":{"KJV":{"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit."}},"definableWords":["spirit"],"peopleInVerse":[]},"7":{"text":"Then I returned, and I saw vanity under the sun.","ref":"Ecclesiastes 4:7","synthesized":"Then I returned, and I saw vanity under the sun.","sources":{"KJV":{"text":"Then I returned, and I saw vanity under the sun."}},"definableWords":["saw"],"peopleInVerse":[]},"8":{"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail.","ref":"Ecclesiastes 4:8","synthesized":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail.","sources":{"KJV":{"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail."}},"definableWords":["one","brother","soul","good"],"peopleInVerse":[]},"9":{"text":"Two are better than one; because they have a good reward for their labour.","ref":"Ecclesiastes 4:9","synthesized":"Two are better than one; because they have a good reward for their labour.","sources":{"KJV":{"text":"Two are better than one; because they have a good reward for their labour."}},"definableWords":["one","good"],"peopleInVerse":[]},"10":{"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up.","ref":"Ecclesiastes 4:10","synthesized":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up.","sources":{"KJV":{"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up."}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"Again, if two lie together, then they have heat: but how can one be warm alone?","ref":"Ecclesiastes 4:11","synthesized":"Again, if two lie together, then they have heat: but how can one be warm alone?","sources":{"KJV":{"text":"Again, if two lie together, then they have heat: but how can one be warm alone?"}},"definableWords":["one"],"peopleInVerse":[]},"12":{"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken.","ref":"Ecclesiastes 4:12","synthesized":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken.","sources":{"KJV":{"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken."}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished.","ref":"Ecclesiastes 4:13","synthesized":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished.","sources":{"KJV":{"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished."}},"definableWords":["king"],"peopleInVerse":[]},"14":{"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor.","ref":"Ecclesiastes 4:14","synthesized":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor.","sources":{"KJV":{"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor."}},"definableWords":["reign","kingdom"],"peopleInVerse":[]},"15":{"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead.","ref":"Ecclesiastes 4:15","synthesized":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead.","sources":{"KJV":{"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead."}},"definableWords":["living","walk"],"peopleInVerse":[]},"16":{"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit.","ref":"Ecclesiastes 4:16","synthesized":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit.","sources":{"KJV":{"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit."}},"definableWords":["people","spirit"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"Ecclesiastes 5","verses":{"1":{"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil.","ref":"Ecclesiastes 5:1","synthesized":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil.","sources":{"KJV":{"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil."}},"definableWords":["keep","house","God","sacrifice","evil"],"peopleInVerse":[]},"2":{"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few.","ref":"Ecclesiastes 5:2","synthesized":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few.","sources":{"KJV":{"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few."}},"definableWords":["God","heaven","earth"],"peopleInVerse":[]},"3":{"text":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words.","ref":"Ecclesiastes 5:3","synthesized":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words.","sources":{"KJV":{"text":"For a dream cometh through the multitude of business; and a fool’s voice is known by multitude of words."}},"definableWords":["voice"],"peopleInVerse":[]},"4":{"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed.","ref":"Ecclesiastes 5:4","synthesized":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed.","sources":{"KJV":{"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed."}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay.","ref":"Ecclesiastes 5:5","synthesized":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay.","sources":{"KJV":{"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?","ref":"Ecclesiastes 5:6","synthesized":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?","sources":{"KJV":{"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?"}},"definableWords":["flesh","sin","God","voice","work"],"peopleInVerse":[]},"7":{"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God.","ref":"Ecclesiastes 5:7","synthesized":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God.","sources":{"KJV":{"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God."}},"definableWords":["fear","God"],"peopleInVerse":[]},"8":{"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they.","ref":"Ecclesiastes 5:8","synthesized":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they.","sources":{"KJV":{"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they."}},"definableWords":["judgment","justice"],"peopleInVerse":[]},"9":{"text":"Moreover the profit of the earth is for all: the king himself is served by the field.","ref":"Ecclesiastes 5:9","synthesized":"Moreover the profit of the earth is for all: the king himself is served by the field.","sources":{"KJV":{"text":"Moreover the profit of the earth is for all: the king himself is served by the field."}},"definableWords":["earth","king","field"],"peopleInVerse":[]},"10":{"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity.","ref":"Ecclesiastes 5:10","synthesized":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity.","sources":{"KJV":{"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?","ref":"Ecclesiastes 5:11","synthesized":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?","sources":{"KJV":{"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?"}},"definableWords":["good"],"peopleInVerse":[]},"12":{"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep.","ref":"Ecclesiastes 5:12","synthesized":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep.","sources":{"KJV":{"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep."}},"definableWords":["man","or"],"peopleInVerse":[]},"13":{"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt.","ref":"Ecclesiastes 5:13","synthesized":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt.","sources":{"KJV":{"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt."}},"definableWords":["evil"],"peopleInVerse":[]},"14":{"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand.","ref":"Ecclesiastes 5:14","synthesized":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand.","sources":{"KJV":{"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand."}},"definableWords":["evil","son"],"peopleInVerse":[]},"15":{"text":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand.","ref":"Ecclesiastes 5:15","synthesized":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand.","sources":{"KJV":{"text":"As he came forth of his mother’s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand."}},"definableWords":["mother","naked"],"peopleInVerse":[]},"16":{"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?","ref":"Ecclesiastes 5:16","synthesized":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?","sources":{"KJV":{"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?"}},"definableWords":["evil"],"peopleInVerse":[]},"17":{"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness.","ref":"Ecclesiastes 5:17","synthesized":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness.","sources":{"KJV":{"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness."}},"definableWords":["days","darkness","wrath"],"peopleInVerse":[]},"18":{"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion.","ref":"Ecclesiastes 5:18","synthesized":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion.","sources":{"KJV":{"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion."}},"definableWords":["good","one","days","life","God"],"peopleInVerse":[]},"19":{"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God.","ref":"Ecclesiastes 5:19","synthesized":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God.","sources":{"KJV":{"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God."}},"definableWords":["man","God"],"peopleInVerse":[]},"20":{"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart.","ref":"Ecclesiastes 5:20","synthesized":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart.","sources":{"KJV":{"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart."}},"definableWords":["remember","days","life","God"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"Ecclesiastes 6","verses":{"1":{"text":"There is an evil which I have seen under the sun, and it is common among men:","ref":"Ecclesiastes 6:1","synthesized":"There is an evil which I have seen under the sun, and it is common among men:","sources":{"KJV":{"text":"There is an evil which I have seen under the sun, and it is common among men:"}},"definableWords":["evil","men"],"peopleInVerse":[]},"2":{"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease.","ref":"Ecclesiastes 6:2","synthesized":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease.","sources":{"KJV":{"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease."}},"definableWords":["man","God","soul","evil"],"peopleInVerse":[]},"3":{"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he.","ref":"Ecclesiastes 6:3","synthesized":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he.","sources":{"KJV":{"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he."}},"definableWords":["man","live","years","days","soul","good"],"peopleInVerse":[]},"4":{"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness.","ref":"Ecclesiastes 6:4","synthesized":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness.","sources":{"KJV":{"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness."}},"definableWords":["darkness","name"],"peopleInVerse":[]},"5":{"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other.","ref":"Ecclesiastes 6:5","synthesized":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other.","sources":{"KJV":{"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other."}},"definableWords":["rest"],"peopleInVerse":[]},"6":{"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?","ref":"Ecclesiastes 6:6","synthesized":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?","sources":{"KJV":{"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?"}},"definableWords":["live","years","good","one"],"peopleInVerse":[]},"7":{"text":"All the labour of man is for his mouth, and yet the appetite is not filled.","ref":"Ecclesiastes 6:7","synthesized":"All the labour of man is for his mouth, and yet the appetite is not filled.","sources":{"KJV":{"text":"All the labour of man is for his mouth, and yet the appetite is not filled."}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?","ref":"Ecclesiastes 6:8","synthesized":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?","sources":{"KJV":{"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?"}},"definableWords":["walk","living"],"peopleInVerse":[]},"9":{"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit.","ref":"Ecclesiastes 6:9","synthesized":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit.","sources":{"KJV":{"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit."}},"definableWords":["spirit"],"peopleInVerse":[]},"10":{"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he.","ref":"Ecclesiastes 6:10","synthesized":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he.","sources":{"KJV":{"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he."}},"definableWords":["man"],"peopleInVerse":[]},"11":{"text":"Seeing there be many things that increase vanity, what is man the better?","ref":"Ecclesiastes 6:11","synthesized":"Seeing there be many things that increase vanity, what is man the better?","sources":{"KJV":{"text":"Seeing there be many things that increase vanity, what is man the better?"}},"definableWords":["man"],"peopleInVerse":[]},"12":{"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?","ref":"Ecclesiastes 6:12","synthesized":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?","sources":{"KJV":{"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?"}},"definableWords":["good","man","life","days"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"Ecclesiastes 7","verses":{"1":{"text":"A good name is better than precious ointment; and the day of death than the day of one’s birth.","ref":"Ecclesiastes 7:1","synthesized":"A good name is better than precious ointment; and the day of death than the day of one’s birth.","sources":{"KJV":{"text":"A good name is better than precious ointment; and the day of death than the day of one’s birth."}},"definableWords":["good","name","day","death","one"],"peopleInVerse":[]},"2":{"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart.","ref":"Ecclesiastes 7:2","synthesized":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart.","sources":{"KJV":{"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart."}},"definableWords":["house","men","living"],"peopleInVerse":[]},"3":{"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better.","ref":"Ecclesiastes 7:3","synthesized":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better.","sources":{"KJV":{"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better."}},"definableWords":["made"],"peopleInVerse":[]},"4":{"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.","ref":"Ecclesiastes 7:4","synthesized":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.","sources":{"KJV":{"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth."}},"definableWords":["house"],"peopleInVerse":[]},"5":{"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools.","ref":"Ecclesiastes 7:5","synthesized":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools.","sources":{"KJV":{"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools."}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity.","ref":"Ecclesiastes 7:6","synthesized":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity.","sources":{"KJV":{"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart.","ref":"Ecclesiastes 7:7","synthesized":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart.","sources":{"KJV":{"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart."}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit.","ref":"Ecclesiastes 7:8","synthesized":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit.","sources":{"KJV":{"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit."}},"definableWords":["beginning","spirit"],"peopleInVerse":[]},"9":{"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.","ref":"Ecclesiastes 7:9","synthesized":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.","sources":{"KJV":{"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools."}},"definableWords":["spirit","anger"],"peopleInVerse":[]},"10":{"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this.","ref":"Ecclesiastes 7:10","synthesized":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this.","sources":{"KJV":{"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this."}},"definableWords":["days"],"peopleInVerse":[]},"11":{"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun.","ref":"Ecclesiastes 7:11","synthesized":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun.","sources":{"KJV":{"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun."}},"definableWords":["wisdom","good","see"],"peopleInVerse":[]},"12":{"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it.","ref":"Ecclesiastes 7:12","synthesized":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it.","sources":{"KJV":{"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it."}},"definableWords":["wisdom","knowledge","life"],"peopleInVerse":[]},"13":{"text":"Consider the work of God: for who can make that straight, which he hath made crooked?","ref":"Ecclesiastes 7:13","synthesized":"Consider the work of God: for who can make that straight, which he hath made crooked?","sources":{"KJV":{"text":"Consider the work of God: for who can make that straight, which he hath made crooked?"}},"definableWords":["work","God","make","made"],"peopleInVerse":[]},"14":{"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him.","ref":"Ecclesiastes 7:14","synthesized":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him.","sources":{"KJV":{"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him."}},"definableWords":["day","God","one","man"],"peopleInVerse":[]},"15":{"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness.","ref":"Ecclesiastes 7:15","synthesized":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness.","sources":{"KJV":{"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness."}},"definableWords":["days","man","righteousness","life"],"peopleInVerse":[]},"16":{"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself ?","ref":"Ecclesiastes 7:16","synthesized":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself ?","sources":{"KJV":{"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself ?"}},"definableWords":["righteous","make"],"peopleInVerse":[]},"17":{"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?","ref":"Ecclesiastes 7:17","synthesized":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?","sources":{"KJV":{"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?"}},"definableWords":["die"],"peopleInVerse":[]},"18":{"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all.","ref":"Ecclesiastes 7:18","synthesized":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all.","sources":{"KJV":{"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all."}},"definableWords":["good","God"],"peopleInVerse":[]},"19":{"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city.","ref":"Ecclesiastes 7:19","synthesized":"Wisdom strengtheneth the wise more than ten mighty men which are in the city.","sources":{"KJV":{"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city."}},"definableWords":["wisdom","mighty","men"],"peopleInVerse":[]},"20":{"text":"For there is not a just man upon earth, that doeth good, and sinneth not.","ref":"Ecclesiastes 7:20","synthesized":"For there is not a just man upon earth, that doeth good, and sinneth not.","sources":{"KJV":{"text":"For there is not a just man upon earth, that doeth good, and sinneth not."}},"definableWords":["man","earth","good"],"peopleInVerse":[]},"21":{"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:","ref":"Ecclesiastes 7:21","synthesized":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:","sources":{"KJV":{"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:"}},"definableWords":["servant","curse"],"peopleInVerse":[]},"22":{"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others.","ref":"Ecclesiastes 7:22","synthesized":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others.","sources":{"KJV":{"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others."}},"definableWords":["cursed"],"peopleInVerse":[]},"23":{"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me.","ref":"Ecclesiastes 7:23","synthesized":"All this have I proved by wisdom: I said, I will be wise; but it was far from me.","sources":{"KJV":{"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me."}},"definableWords":["wisdom"],"peopleInVerse":[]},"24":{"text":"That which is far off, and exceeding deep, who can find it out?","ref":"Ecclesiastes 7:24","synthesized":"That which is far off, and exceeding deep, who can find it out?","sources":{"KJV":{"text":"That which is far off, and exceeding deep, who can find it out?"}},"definableWords":["deep"],"peopleInVerse":[]},"25":{"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:","ref":"Ecclesiastes 7:25","synthesized":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:","sources":{"KJV":{"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:"}},"definableWords":["wisdom"],"peopleInVerse":[]},"26":{"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her.","ref":"Ecclesiastes 7:26","synthesized":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her.","sources":{"KJV":{"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her."}},"definableWords":["death","woman","God"],"peopleInVerse":[]},"27":{"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:","ref":"Ecclesiastes 7:27","synthesized":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:","sources":{"KJV":{"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:"}},"definableWords":["one"],"peopleInVerse":[]},"28":{"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found.","ref":"Ecclesiastes 7:28","synthesized":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found.","sources":{"KJV":{"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found."}},"definableWords":["soul","one","man","woman"],"peopleInVerse":[]},"29":{"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions.","ref":"Ecclesiastes 7:29","synthesized":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions.","sources":{"KJV":{"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions."}},"definableWords":["God","made","man"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"Ecclesiastes 8","verses":{"1":{"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed.","ref":"Ecclesiastes 8:1","synthesized":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed.","sources":{"KJV":{"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man’s wisdom maketh his face to shine, and the boldness of his face shall be changed."}},"definableWords":["man","wisdom"],"peopleInVerse":[]},"2":{"text":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God.","ref":"Ecclesiastes 8:2","synthesized":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God.","sources":{"KJV":{"text":"I counsel thee to keep the king’s commandment, and that in regard of the oath of God."}},"definableWords":["keep","king","God"],"peopleInVerse":[]},"3":{"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him.","ref":"Ecclesiastes 8:3","synthesized":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him.","sources":{"KJV":{"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him."}},"definableWords":["evil"],"peopleInVerse":[]},"4":{"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?","ref":"Ecclesiastes 8:4","synthesized":"Where the word of a king is, there is power: and who may say unto him, What doest thou?","sources":{"KJV":{"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?"}},"definableWords":["word","king"],"peopleInVerse":[]},"5":{"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment.","ref":"Ecclesiastes 8:5","synthesized":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment.","sources":{"KJV":{"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man’s heart discerneth both time and judgment."}},"definableWords":["evil","man","judgment"],"peopleInVerse":[]},"6":{"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him.","ref":"Ecclesiastes 8:6","synthesized":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him.","sources":{"KJV":{"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him."}},"definableWords":["judgment","man","great"],"peopleInVerse":[]},"7":{"text":"For he knoweth not that which shall be: for who can tell him when it shall be?","ref":"Ecclesiastes 8:7","synthesized":"For he knoweth not that which shall be: for who can tell him when it shall be?","sources":{"KJV":{"text":"For he knoweth not that which shall be: for who can tell him when it shall be?"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it.","ref":"Ecclesiastes 8:8","synthesized":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it.","sources":{"KJV":{"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it."}},"definableWords":["man","spirit","day","death"],"peopleInVerse":[]},"9":{"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt.","ref":"Ecclesiastes 8:9","synthesized":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt.","sources":{"KJV":{"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt."}},"definableWords":["work","one","man"],"peopleInVerse":[]},"10":{"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity.","ref":"Ecclesiastes 8:10","synthesized":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity.","sources":{"KJV":{"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity."}},"definableWords":["saw"],"peopleInVerse":[]},"11":{"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.","ref":"Ecclesiastes 8:11","synthesized":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.","sources":{"KJV":{"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil."}},"definableWords":["evil","work","sons","men"],"peopleInVerse":[]},"12":{"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:","ref":"Ecclesiastes 8:12","synthesized":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:","sources":{"KJV":{"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:"}},"definableWords":["evil","days","fear","God"],"peopleInVerse":[]},"13":{"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God.","ref":"Ecclesiastes 8:13","synthesized":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God.","sources":{"KJV":{"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God."}},"definableWords":["days","God"],"peopleInVerse":[]},"14":{"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity.","ref":"Ecclesiastes 8:14","synthesized":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity.","sources":{"KJV":{"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity."}},"definableWords":["earth","men","work","righteous"],"peopleInVerse":[]},"15":{"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun.","ref":"Ecclesiastes 8:15","synthesized":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun.","sources":{"KJV":{"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun."}},"definableWords":["man","days","life","God"],"peopleInVerse":[]},"16":{"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)","ref":"Ecclesiastes 8:16","synthesized":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)","sources":{"KJV":{"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)"}},"definableWords":["wisdom","see","earth","day","night"],"peopleInVerse":[]},"17":{"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea farther; though a wise man think to know it, yet shall he not be able to find it.","ref":"Ecclesiastes 8:17","synthesized":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea farther; though a wise man think to know it, yet shall he not be able to find it.","sources":{"KJV":{"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea farther; though a wise man think to know it, yet shall he not be able to find it."}},"definableWords":["work","God","man"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"Ecclesiastes 9","verses":{"1":{"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them.","ref":"Ecclesiastes 9:1","synthesized":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them.","sources":{"KJV":{"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them."}},"definableWords":["righteous","works","God","man","love","or"],"peopleInVerse":[]},"2":{"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath.","ref":"Ecclesiastes 9:2","synthesized":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath.","sources":{"KJV":{"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath."}},"definableWords":["one","righteous","good"],"peopleInVerse":[]},"3":{"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.","ref":"Ecclesiastes 9:3","synthesized":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.","sources":{"KJV":{"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead."}},"definableWords":["evil","one","sons","men","live"],"peopleInVerse":[]},"4":{"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion.","ref":"Ecclesiastes 9:4","synthesized":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion.","sources":{"KJV":{"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion."}},"definableWords":["living","lion"],"peopleInVerse":[]},"5":{"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten.","ref":"Ecclesiastes 9:5","synthesized":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten.","sources":{"KJV":{"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten."}},"definableWords":["living","die"],"peopleInVerse":[]},"6":{"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun.","ref":"Ecclesiastes 9:6","synthesized":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun.","sources":{"KJV":{"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun."}},"definableWords":["love"],"peopleInVerse":[]},"7":{"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works.","ref":"Ecclesiastes 9:7","synthesized":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works.","sources":{"KJV":{"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works."}},"definableWords":["way","God","works"],"peopleInVerse":[]},"8":{"text":"Let thy garments be always white; and let thy head lack no ointment.","ref":"Ecclesiastes 9:8","synthesized":"Let thy garments be always white; and let thy head lack no ointment.","sources":{"KJV":{"text":"Let thy garments be always white; and let thy head lack no ointment."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun.","ref":"Ecclesiastes 9:9","synthesized":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun.","sources":{"KJV":{"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun."}},"definableWords":["live","wife","days","life"],"peopleInVerse":[]},"10":{"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest.","ref":"Ecclesiastes 9:10","synthesized":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest.","sources":{"KJV":{"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest."}},"definableWords":["work","knowledge","wisdom"],"peopleInVerse":[]},"11":{"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all.","ref":"Ecclesiastes 9:11","synthesized":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all.","sources":{"KJV":{"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all."}},"definableWords":["saw","strong","men"],"peopleInVerse":[]},"12":{"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them.","ref":"Ecclesiastes 9:12","synthesized":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them.","sources":{"KJV":{"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them."}},"definableWords":["man","evil","birds","sons","men"],"peopleInVerse":[]},"13":{"text":"This wisdom have I seen also under the sun, and it seemed great unto me:","ref":"Ecclesiastes 9:13","synthesized":"This wisdom have I seen also under the sun, and it seemed great unto me:","sources":{"KJV":{"text":"This wisdom have I seen also under the sun, and it seemed great unto me:"}},"definableWords":["wisdom","great"],"peopleInVerse":[]},"14":{"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:","ref":"Ecclesiastes 9:14","synthesized":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:","sources":{"KJV":{"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:"}},"definableWords":["men","great","king"],"peopleInVerse":[]},"15":{"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man.","ref":"Ecclesiastes 9:15","synthesized":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man.","sources":{"KJV":{"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man."}},"definableWords":["man","wisdom","remembered"],"peopleInVerse":[]},"16":{"text":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard.","ref":"Ecclesiastes 9:16","synthesized":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard.","sources":{"KJV":{"text":"Then said I, Wisdom is better than strength: nevertheless the poor man’s wisdom is despised, and his words are not heard."}},"definableWords":["wisdom","man"],"peopleInVerse":[]},"17":{"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools.","ref":"Ecclesiastes 9:17","synthesized":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools.","sources":{"KJV":{"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools."}},"definableWords":["men"],"peopleInVerse":[]},"18":{"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good.","ref":"Ecclesiastes 9:18","synthesized":"Wisdom is better than weapons of war: but one sinner destroyeth much good.","sources":{"KJV":{"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good."}},"definableWords":["wisdom","one","good"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"Ecclesiastes 10","verses":{"1":{"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour.","ref":"Ecclesiastes 10:1","synthesized":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour.","sources":{"KJV":{"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour."}},"definableWords":["wisdom"],"peopleInVerse":[]},"2":{"text":"A wise man’s heart is at his right hand; but a fool’s heart at his left.","ref":"Ecclesiastes 10:2","synthesized":"A wise man’s heart is at his right hand; but a fool’s heart at his left.","sources":{"KJV":{"text":"A wise man’s heart is at his right hand; but a fool’s heart at his left."}},"definableWords":["man"],"peopleInVerse":[]},"3":{"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool.","ref":"Ecclesiastes 10:3","synthesized":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool.","sources":{"KJV":{"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool."}},"definableWords":["way","wisdom","one"],"peopleInVerse":[]},"4":{"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences.","ref":"Ecclesiastes 10:4","synthesized":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences.","sources":{"KJV":{"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences."}},"definableWords":["spirit","ruler","great"],"peopleInVerse":[]},"5":{"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:","ref":"Ecclesiastes 10:5","synthesized":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:","sources":{"KJV":{"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:"}},"definableWords":["evil","ruler"],"peopleInVerse":[]},"6":{"text":"Folly is set in great dignity, and the rich sit in low place.","ref":"Ecclesiastes 10:6","synthesized":"Folly is set in great dignity, and the rich sit in low place.","sources":{"KJV":{"text":"Folly is set in great dignity, and the rich sit in low place."}},"definableWords":["great"],"peopleInVerse":[]},"7":{"text":"I have seen servants upon horses, and princes walking as servants upon the earth.","ref":"Ecclesiastes 10:7","synthesized":"I have seen servants upon horses, and princes walking as servants upon the earth.","sources":{"KJV":{"text":"I have seen servants upon horses, and princes walking as servants upon the earth."}},"definableWords":["servants","earth"],"peopleInVerse":[]},"8":{"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him.","ref":"Ecclesiastes 10:8","synthesized":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him.","sources":{"KJV":{"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him."}},"definableWords":["serpent"],"peopleInVerse":[]},"9":{"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby.","ref":"Ecclesiastes 10:9","synthesized":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby.","sources":{"KJV":{"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct.","ref":"Ecclesiastes 10:10","synthesized":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct.","sources":{"KJV":{"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct."}},"definableWords":["wisdom"],"peopleInVerse":[]},"11":{"text":"Surely the serpent will bite without enchantment; and a babbler is no better.","ref":"Ecclesiastes 10:11","synthesized":"Surely the serpent will bite without enchantment; and a babbler is no better.","sources":{"KJV":{"text":"Surely the serpent will bite without enchantment; and a babbler is no better."}},"definableWords":["serpent"],"peopleInVerse":[]},"12":{"text":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself.","ref":"Ecclesiastes 10:12","synthesized":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself.","sources":{"KJV":{"text":"The words of a wise man’s mouth are gracious; but the lips of a fool will swallow up himself."}},"definableWords":["man"],"peopleInVerse":[]},"13":{"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness.","ref":"Ecclesiastes 10:13","synthesized":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness.","sources":{"KJV":{"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness."}},"definableWords":["beginning"],"peopleInVerse":[]},"14":{"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?","ref":"Ecclesiastes 10:14","synthesized":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?","sources":{"KJV":{"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?"}},"definableWords":["man"],"peopleInVerse":[]},"15":{"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city.","ref":"Ecclesiastes 10:15","synthesized":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city.","sources":{"KJV":{"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city."}},"definableWords":["one"],"peopleInVerse":[]},"16":{"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!","ref":"Ecclesiastes 10:16","synthesized":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!","sources":{"KJV":{"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!"}},"definableWords":["land","king"],"peopleInVerse":[]},"17":{"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!","ref":"Ecclesiastes 10:17","synthesized":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!","sources":{"KJV":{"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!"}},"definableWords":["blessed","land","king","son"],"peopleInVerse":[]},"18":{"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through.","ref":"Ecclesiastes 10:18","synthesized":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through.","sources":{"KJV":{"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through."}},"definableWords":["house"],"peopleInVerse":[]},"19":{"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things.","ref":"Ecclesiastes 10:19","synthesized":"A feast is made for laughter, and wine maketh merry: but money answereth all things.","sources":{"KJV":{"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things."}},"definableWords":["made"],"peopleInVerse":[]},"20":{"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter.","ref":"Ecclesiastes 10:20","synthesized":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter.","sources":{"KJV":{"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter."}},"definableWords":["curse","king","bird","voice"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"Ecclesiastes 11","verses":{"1":{"text":"Cast thy bread upon the waters: for thou shalt find it after many days.","ref":"Ecclesiastes 11:1","synthesized":"Cast thy bread upon the waters: for thou shalt find it after many days.","sources":{"KJV":{"text":"Cast thy bread upon the waters: for thou shalt find it after many days."}},"definableWords":["waters","days"],"peopleInVerse":[]},"2":{"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth.","ref":"Ecclesiastes 11:2","synthesized":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth.","sources":{"KJV":{"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth."}},"definableWords":["evil","earth"],"peopleInVerse":[]},"3":{"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be.","ref":"Ecclesiastes 11:3","synthesized":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be.","sources":{"KJV":{"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be."}},"definableWords":["earth","tree","or"],"peopleInVerse":[]},"4":{"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap.","ref":"Ecclesiastes 11:4","synthesized":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap.","sources":{"KJV":{"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all.","ref":"Ecclesiastes 11:5","synthesized":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all.","sources":{"KJV":{"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all."}},"definableWords":["way","spirit","bones","works","God"],"peopleInVerse":[]},"6":{"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good.","ref":"Ecclesiastes 11:6","synthesized":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good.","sources":{"KJV":{"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good."}},"definableWords":["seed","or","good"],"peopleInVerse":[]},"7":{"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:","ref":"Ecclesiastes 11:7","synthesized":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:","sources":{"KJV":{"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:"}},"definableWords":["light"],"peopleInVerse":[]},"8":{"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity.","ref":"Ecclesiastes 11:8","synthesized":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity.","sources":{"KJV":{"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity."}},"definableWords":["man","live","years","remember","days","darkness"],"peopleInVerse":[]},"9":{"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment.","ref":"Ecclesiastes 11:9","synthesized":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment.","sources":{"KJV":{"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment."}},"definableWords":["man","days","walk","God","judgment"],"peopleInVerse":[]},"10":{"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity.","ref":"Ecclesiastes 11:10","synthesized":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity.","sources":{"KJV":{"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity."}},"definableWords":["evil","flesh"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"Ecclesiastes 12","verses":{"1":{"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;","ref":"Ecclesiastes 12:1","synthesized":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;","sources":{"KJV":{"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;"}},"definableWords":["remember","days","evil","years"],"peopleInVerse":[]},"2":{"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:","ref":"Ecclesiastes 12:2","synthesized":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:","sources":{"KJV":{"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:"}},"definableWords":["or","light"],"peopleInVerse":[]},"3":{"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,","ref":"Ecclesiastes 12:3","synthesized":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,","sources":{"KJV":{"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,"}},"definableWords":["day","house","strong","men"],"peopleInVerse":[]},"4":{"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;","ref":"Ecclesiastes 12:4","synthesized":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;","sources":{"KJV":{"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;"}},"definableWords":["voice","bird","daughters"],"peopleInVerse":[]},"5":{"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:","ref":"Ecclesiastes 12:5","synthesized":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:","sources":{"KJV":{"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:"}},"definableWords":["way","tree","man"],"peopleInVerse":[]},"6":{"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern.","ref":"Ecclesiastes 12:6","synthesized":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern.","sources":{"KJV":{"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern."}},"definableWords":["or"],"peopleInVerse":[]},"7":{"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it.","ref":"Ecclesiastes 12:7","synthesized":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it.","sources":{"KJV":{"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it."}},"definableWords":["earth","spirit","God"],"peopleInVerse":[]},"8":{"text":"Vanity of vanities, saith the preacher; all is vanity.","ref":"Ecclesiastes 12:8","synthesized":"Vanity of vanities, saith the preacher; all is vanity.","sources":{"KJV":{"text":"Vanity of vanities, saith the preacher; all is vanity."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs.","ref":"Ecclesiastes 12:9","synthesized":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs.","sources":{"KJV":{"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs."}},"definableWords":["people","knowledge","good"],"peopleInVerse":[]},"10":{"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth.","ref":"Ecclesiastes 12:10","synthesized":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth.","sources":{"KJV":{"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd.","ref":"Ecclesiastes 12:11","synthesized":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd.","sources":{"KJV":{"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd."}},"definableWords":["one"],"peopleInVerse":[]},"12":{"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.","ref":"Ecclesiastes 12:12","synthesized":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.","sources":{"KJV":{"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh."}},"definableWords":["son","flesh"],"peopleInVerse":[]},"13":{"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man.","ref":"Ecclesiastes 12:13","synthesized":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man.","sources":{"KJV":{"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man."}},"definableWords":["fear","God","keep","man"],"peopleInVerse":[]},"14":{"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.","ref":"Ecclesiastes 12:14","synthesized":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.","sources":{"KJV":{"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil."}},"definableWords":["God","work","judgment","good","or","evil"],"peopleInVerse":[]}}}};